import (
	addondiff "github.com/openmeterio/openmeter/openmeter/subscription/addon/diff"
	"github.com/openmeterio/openmeter/openmeter/subscription"
)

diffable, err := addondiff.GetDiffableFromAddon(subView, subsAdd)
if err != nil { return err }
if diffable == nil { return nil } // no instances

spec := subView.Spec
if err := spec.Apply(diffable.GetApplies(), subscription.ApplyContext{CurrentTime: now}); err != nil {
	return err
}
// later, to undo:
if err := spec.Apply(diffable.GetRestores(), subscription.ApplyContext{CurrentTime: now}); err != nil {
	return err
}

import (
	subscriptionaddonrepo "github.com/openmeterio/openmeter/openmeter/subscription/addon/repo"
	"github.com/openmeterio/openmeter/openmeter/ent/db"
)

repo := subscriptionaddonrepo.NewSubscriptionAddonRepo(dbClient)
id, err := repo.Create(ctx, ns, subscriptionaddon.CreateSubscriptionAddonRepositoryInput{
	AddonID:        addonID,
	SubscriptionID: subID,
})
// ctx carries the tx — repo.Create rebinds automatically via TransactingRepo
